var elapsed = 0;
        return {
          draw: function(ctx, W, H, t, dt) {
            elapsed += Math.min(dt || 0, 0.05);
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, W, H);

            var pad = Math.max(10, W * 0.04);
            var colW = W / 2 - pad * 1.5;
            var leftX = pad;
            var rightX = W / 2 + pad / 2;
            var titleSize = Math.max(9, Math.min(13, colW / 11));
            var labelSize = Math.max(8, Math.min(11, colW / 13));

            function fitText(text, maxWidth, baseSize) {
              var size = baseSize;
              ctx.font = 'bold ' + size + 'px Arial';
              while (ctx.measureText(text).width > maxWidth && size > 7) {
                size -= 1;
                ctx.font = 'bold ' + size + 'px Arial';
              }
              return size;
            }

            // Titles (two lines each, sized to fit their own column)
            ctx.fillStyle = '#333';
            ctx.textAlign = 'left';
            var t1Size = fitText('Classical Scale', colW, titleSize);
            ctx.font = 'bold ' + t1Size + 'px Arial';
            ctx.fillText('Classical Scale', leftX, 22);
            ctx.font = (t1Size - 1) + 'px Arial';
            ctx.fillText('(Everyday)', leftX, 22 + t1Size + 2);

            var t2Size = fitText('Quantum Scale', colW, titleSize);
            ctx.font = 'bold ' + t2Size + 'px Arial';
            ctx.fillText('Quantum Scale', rightX, 22);
            ctx.font = (t2Size - 1) + 'px Arial';
            ctx.fillText('(Atomic)', rightX, 22 + t2Size + 2);

            var contentTop = 60;

            // Classical side - smooth trajectory, clamped to its column
            var cCenterX = leftX + colW / 2;
            var cW = Math.min(colW - 20, 100);
            ctx.strokeStyle = '#DC2626';
            ctx.lineWidth = 2;
            ctx.beginPath();
            for (var i = 0; i <= cW; i += 5) {
              var px = leftX + 10 + i;
              var py = contentTop + 40 + Math.sin(i / 20) * 25;
              if (i === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
            }
            ctx.stroke();

            var ballPos = (elapsed * 40) % cW;
            var ballX = leftX + 10 + ballPos;
            ctx.fillStyle = '#DC2626';
            ctx.beginPath();
            ctx.arc(ballX, contentTop + 40 + Math.sin(ballPos / 20) * 25, 7, 0, Math.PI * 2);
            ctx.fill();

            ctx.fillStyle = '#666';
            ctx.font = labelSize + 'px Arial';
            ctx.fillText('Smooth path', leftX, contentTop + 100);
            ctx.fillText('Predictable', leftX, contentTop + 100 + labelSize + 4);

            // Quantum side - fuzzy/probability, clamped to its column.
            // Positions drift slowly (seeded, not re-randomized every frame)
            // so it reads as a calm cloud instead of 60fps flicker.
            var cloudPhase = Math.floor(elapsed * 1.5);
            function seeded(i, salt) {
              var x = Math.sin(i * 12.9898 + salt * 78.233) * 43758.5453;
              return x - Math.floor(x);
            }
            ctx.fillStyle = 'rgba(59, 130, 246, 0.3)';
            for (var j = 0; j < 16; j++) {
              var qx = rightX + 10 + seeded(j, cloudPhase) * (colW - 30);
              var qy = contentTop + 10 + seeded(j, cloudPhase + 1) * 70;
              var qr = seeded(j, cloudPhase + 2) * 5 + 1;
              ctx.beginPath();
              ctx.arc(qx, qy, qr, 0, Math.PI * 2);
              ctx.fill();
            }

            ctx.fillStyle = '#3B82F6';
            ctx.beginPath();
            ctx.arc(rightX + colW / 2, contentTop + 45, 9, 0, Math.PI * 2);
            ctx.fill();

            ctx.fillStyle = '#666';
            ctx.font = labelSize + 'px Arial';
            ctx.fillText('Probability cloud', rightX, contentTop + 100);
            ctx.fillText('Uncertain', rightX, contentTop + 100 + labelSize + 4);
          }
        };
